# Base module defining geometric shapes

class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @virtual
    def area(self) -> float:
        return 0.0

    @virtual
    def describe(self) -> str:
        return f"Shape: {self.name}"

interface IDrawable:
    def draw(self) -> str

